import{j as i,b as t,c as e,aa as a}from"./chunks/framework.Bxf40uRC.js";const x=JSON.parse('{"title":"Linux面试高频","description":"","frontmatter":{},"headers":[],"relativePath":"Linux/高频考点.md","filePath":"Linux/高频考点.md","lastUpdated":null}'),l={name:"Linux/高频考点.md"},n=a('<h1 id="linux面试高频" tabindex="-1">Linux面试高频 <a class="header-anchor" href="#linux面试高频" aria-label="Permalink to &quot;Linux面试高频&quot;">​</a></h1><ol><li>文件权限怎么看？文件权限有哪些？分别是什么？怎么更改文件权限？</li><li>Epoll的ET模式和LT模式？</li><li>linux中的kill，find，cp等命令？</li><li><h2 id="软链接和硬链接的区别-怎么创建软链接-怎么创建硬链接-把源文件删除-哪个链接可以继续访问到原始文件-为什么-删除文件的实际操作是什么" tabindex="-1">软链接和硬链接的区别？怎么创建软链接？怎么创建硬链接？把源文件删除，哪个链接可以继续访问到原始文件？为什么？删除文件的实际操作是什么？ <a class="header-anchor" href="#软链接和硬链接的区别-怎么创建软链接-怎么创建硬链接-把源文件删除-哪个链接可以继续访问到原始文件-为什么-删除文件的实际操作是什么" aria-label="Permalink to &quot;软链接和硬链接的区别？怎么创建软链接？怎么创建硬链接？把源文件删除，哪个链接可以继续访问到原始文件？为什么？删除文件的实际操作是什么？&quot;">​</a></h2></li><li>文件的三种时间(mtime, atime, ctime)，分别在什么时候会发生改变?解释一下mtime，atime，ctime分别是什么? <ul><li><strong>mtime</strong>（修改时间）：文件内容最后一次被修改的时间。当你用编辑器修改文件内容并保存时，修改时间会被更新。</li><li><strong>atime</strong>（访问时间）：文件最后一次被访问的时间。当文件被读取、执行或访问时，访问时间会被更新。但需要注意的是，现代文件系统通常会将 atime 的更新延迟到一定程度，以提高性能，因此这个时间不一定总是准确的。</li><li><strong>ctime</strong>（状态改变时间）：文件的状态最后一次发生改变的时间。这个状态包括文件的权限和所有权的改变，以及文件内容的改变。除非文件内容发生了改变，否则 ctime 并不会更新。所以，当你修改文件权限、更改所有者或者修改文件元数据时，ctime 会被更新。</li></ul></li><li>Linux监控网络带宽的命令，查看特定进程的占用网络资源情况命令？</li></ol>',2),o=[n];function r(s,_,c,m,d,u){return t(),e("div",null,o)}const p=i(l,[["render",r]]);export{x as __pageData,p as default};
